export function getPageBySlug(slug: string): NichePage | undefined {
  return NICHE_PAGES.find((p) => p.slug === slug);
}

export function getRelatedPages(slugs: string[]): NichePage[] {
  return slugs
    .map((s) => getPageBySlug(s))
    .filter((p): p is NichePage => p !== undefined);
}

